// Contoh dokumen mahasiswa di MongoDB
// Satu dokumen = satu baris di SQL
{
  "_id": ObjectId("64f2a8b3c9e1234567890abc"),  // auto-generated, unik

  // Field sederhana
  "nim":   "2021001",
  "nama":  "Budi Santoso",
  "email": "budi@email.com",
  "ipk":   3.85,
  "aktif": true,

  // Embedded document: data alamat
  "alamat": {
    "jalan":    "Jl. Merdeka No. 10",
    "kelurahan": "Bukit Lama",
    "kota":     "Palembang",
    "provinsi": "Sumatera Selatan",
    "kodePos":  "30128"
  },

  // Array of strings
  "hobi": ["coding", "membaca", "hiking"],

  // Array of embedded documents
  "riwayat_nilai": [
    { "matkul": "Algoritma",    "nilai": 85, "semester": "2021/1" },
    { "matkul": "Basis Data",   "nilai": 90, "semester": "2021/2" },
    { "matkul": "Jaringan Kom", "nilai": 78, "semester": "2022/1" }
  ],

  // Reference ke dokumen lain (seperti FK di SQL)
  "jurusan_id": ObjectId("64f2a8b3c9e1234567890def"),

  // Timestamp otomatis
  "createdAt": ISODate("2024-01-15T08:30:00.000Z"),
  "updatedAt": ISODate("2024-03-20T14:22:10.000Z")
}

// Dokumen lain dalam COLLECTION YANG SAMA
// bisa punya STRUKTUR YANG BERBEDA!
{
  "_id": ObjectId("64f2a8b3c9e1234567890abd"),
  "nim":  "2021002",
  "nama": "Siti Rahayu",
  "email": "siti@email.com",
  // Tidak ada field 'alamat' — valid di MongoDB!
  // Tidak ada field 'hobi' — juga valid!
  "jurusan_id": ObjectId("64f2a8b3c9e1234567890def"),
  "beasiswa": "KIP-Kuliah"  // field baru yang tidak ada di dokumen lain — tetap valid!
}

// Buka mongosh di terminal: mongosh
// Pilih/buat database
use web_belajar

// ==========================================
// INSERT
// ==========================================

// insertOne
db.mahasiswa.insertOne({
  nim:   "2021001",
  nama:  "Budi Santoso",
  email: "budi@email.com",
  ipk:   3.85,
  aktif: true,
  alamat: { kota: "Palembang", provinsi: "Sumatera Selatan" },
  hobi:   ["coding", "membaca"]
})
// Output: { acknowledged: true, insertedId: ObjectId("...") }

// insertMany
db.mahasiswa.insertMany([
  { nim: "2021002", nama: "Siti Rahayu",  email: "siti@email.com",  ipk: 3.70 },
  { nim: "2021003", nama: "Ahmad Fauzi",  email: "ahmad@email.com", ipk: 3.55 },
  { nim: "2021004", nama: "Dewi Lestari", email: "dewi@email.com",  ipk: 3.90 }
])

// ==========================================
// FIND (READ)
// ==========================================

// Ambil semua
db.mahasiswa.find()
db.mahasiswa.find().pretty()  // format lebih rapi

// Filter
db.mahasiswa.find({ aktif: true })
db.mahasiswa.find({ "alamat.kota": "Palembang" })  // dot notation untuk nested field

// Projection: pilih kolom yang mau ditampilkan
db.mahasiswa.find(
  { aktif: true },              // filter
  { nama: 1, nim: 1, ipk: 1 }  // projection: 1=tampilkan, 0=sembunyikan
)
db.mahasiswa.find({}, { _id: 0, nama: 1, email: 1 })  // _id: 0 untuk sembunyikan _id

// findOne
db.mahasiswa.findOne({ nim: "2021001" })

// Sort, limit, skip
db.mahasiswa.find({ aktif: true })
  .sort({ ipk: -1, nama: 1 })  // -1 = descending, 1 = ascending
  .limit(10)
  .skip(0)

// countDocuments
db.mahasiswa.countDocuments({ aktif: true })

// ==========================================
// UPDATE
// ==========================================

// updateOne: gunakan operator $set untuk update sebagian field
db.mahasiswa.updateOne(
  { nim: "2021001" },          // filter
  { $set: { ipk: 3.95 } }      // update: HANYA ubah field ipk
)
// JANGAN: { ipk: 3.95 } — ini akan MENGHAPUS semua field lain!

// Update field nested
db.mahasiswa.updateOne(
  { nim: "2021001" },
  { $set: { "alamat.kota": "Yogyakarta" } }  // dot notation untuk nested
)

// Tambah/kurangi angka dengan $inc
db.mahasiswa.updateOne(
  { nim: "2021001" },
  { $inc: { poin_reward: 10 } }  // tambah 10 ke poin_reward
)

// Tambah elemen ke array dengan $push
db.mahasiswa.updateOne(
  { nim: "2021001" },
  { $push: { hobi: "hiking" } }
)

// updateMany
db.mahasiswa.updateMany(
  { ipk: { $lt: 2.0 } },       // filter: IPK di bawah 2.0
  { $set: { aktif: false } }   // nonaktifkan semua
)

// ==========================================
// DELETE
// ==========================================

// deleteOne
db.mahasiswa.deleteOne({ nim: "2021004" })

// deleteMany
db.mahasiswa.deleteMany({ aktif: false })

// Hapus seluruh isi collection (tapi collection tetap ada)
db.mahasiswa.deleteMany({})

// ==========================================
// OPERATOR PERBANDINGAN
// ==========================================

// IPK di atas 3.5
db.mahasiswa.find({ ipk: { $gt: 3.5 } })

// IPK antara 3.0 dan 3.5 (inklusif)
db.mahasiswa.find({ ipk: { $gte: 3.0, $lte: 3.5 } })

// Mahasiswa dari kota Palembang atau Yogyakarta
db.mahasiswa.find({ "alamat.kota": { $in: ["Palembang", "Yogyakarta", "Bandung"] } })

// Bukan dari jurusan TI
db.mahasiswa.find({ jurusan: { $ne: "Teknik Informatika" } })

// ==========================================
// OPERATOR LOGIKA
// ==========================================

// $and: IPK di atas 3.5 DAN aktif
db.mahasiswa.find({
  $and: [
    { ipk:   { $gt: 3.5 } },
    { aktif: true }
  ]
})
// Shorthand $and yang lebih bersih:
db.mahasiswa.find({ ipk: { $gt: 3.5 }, aktif: true })

// $or: IPK di atas 3.8 ATAU mendapat beasiswa
db.mahasiswa.find({
  $or: [
    { ipk: { $gte: 3.8 } },
    { beasiswa: { $exists: true } }
  ]
})

// Kombinasi $and dan $or
db.mahasiswa.find({
  aktif: true,
  $or: [
    { ipk: { $gte: 3.8 } },
    { beasiswa: "KIP-Kuliah" }
  ]
})

// ==========================================
// OPERATOR ELEMEN
// ==========================================

// Mahasiswa yang memiliki field 'beasiswa'
db.mahasiswa.find({ beasiswa: { $exists: true } })

// Mahasiswa yang TIDAK memiliki field 'no_telepon'
db.mahasiswa.find({ no_telepon: { $exists: false } })

// ==========================================
// OPERATOR ARRAY
// ==========================================

// Memiliki hobi 'coding' (array contains)
db.mahasiswa.find({ hobi: "coding" })

// Memiliki SEMUA hobi ini
db.mahasiswa.find({ hobi: { $all: ["coding", "membaca"] } })

// Array hobi tepat 3 elemen
db.mahasiswa.find({ hobi: { $size: 3 } })

// Cari di array of objects dengan $elemMatch
db.mahasiswa.find({
  riwayat_nilai: {
    $elemMatch: {
      matkul: "Basis Data",
      nilai: { $gte: 85 }
    }
  }
})

// ==========================================
// REGEX: pencarian teks fleksibel
// ==========================================

// Nama yang diawali 'Budi'
db.mahasiswa.find({ nama: { $regex: /^Budi/i } })  // i = case insensitive

// Email dari domain gmail
db.mahasiswa.find({ email: { $regex: /@gmail\.com$/ } })

