const { Mahasiswa } = require('../models/Mahasiswa');

// ==========================================
// VALIDASI SAAT CREATE
// ==========================================
async function buatMahasiswa(data) {
  try {
    const mahasiswaBaru = await Mahasiswa.create(data);
    return mahasiswaBaru;
  } catch (err) {
    // Cek apakah ini ValidationError
    if (err.name === 'ValidationError') {
      // Ekstrak pesan error per field
      const errors = Object.keys(err.errors).reduce((acc, field) => {
        acc[field] = err.errors[field].message;
        return acc;
      }, {});

      // Lempar error yang sudah diformat
      const formatted = new Error('Validasi gagal');
      formatted.statusCode = 400;
      formatted.errors = errors;
      throw formatted;
    }

    // Cek duplicate key error (unique constraint)
    if (err.code === 11000) {
      const field = Object.keys(err.keyValue)[0];
      const value = err.keyValue[field];
      const error = new Error(`${field} '${value}' sudah digunakan`);
      error.statusCode = 409; // Conflict
      throw error;
    }

    throw err; // error lain, lempar ulang
  }
}

// ==========================================
// VALIDASI SAAT UPDATE — runValidators wajib!
// ==========================================
async function updateIPK(id, ipkBaru) {
  const mhs = await Mahasiswa.findByIdAndUpdate(
    id,
    { $set: { ipk: ipkBaru } },
    {
      new:           true,   // kembalikan dokumen setelah update
      runValidators: true,   // WAJIB agar validasi schema berjalan
      context:       'query' // diperlukan untuk beberapa validator
    }
  );

  if (!mhs) throw new Error('Mahasiswa tidak ditemukan');
  return mhs;
}

