const mongoose = require('mongoose');
const { Schema, model } = mongoose;

// ==========================================
// SCHEMA DENGAN REFERENCE
// ==========================================
const mahasiswaSchema = new Schema({
  nim:  String,
  nama: String,
  // Reference ke model Jurusan
  jurusan: {
    type: Schema.Types.ObjectId,
    ref:  'Jurusan',  // nama model yang direferensi
    required: true
  },
  // Reference ke banyak mata kuliah
  mataKuliah: [{
    type: Schema.Types.ObjectId,
    ref:  'MataKuliah'
  }]
}, { timestamps: true });

const Mahasiswa = model('Mahasiswa', mahasiswaSchema);

// ==========================================
// POPULATE: isi referensi dengan data asli
// ==========================================

// Populate satu field
async function getMahasiswaWithJurusan(id) {
  return await Mahasiswa.findById(id)
    .populate('jurusan');  // ganti ObjectId dengan dokumen Jurusan lengkap
}

// Populate dengan projection: hanya ambil field tertentu
async function getMahasiswaDetails(id) {
  return await Mahasiswa.findById(id)
    .populate('jurusan',     'kode nama -_id')  // hanya kode dan nama
    .populate('mataKuliah',  'kode nama sks');  // populate array reference
}

// Nested populate: populate dalam populate
async function getMahasiswaFullDetails(id) {
  return await Mahasiswa.findById(id).populate({
    path: 'jurusan',
    populate: {
      path:   'fakultas',  // populate field 'fakultas' di dalam dokumen Jurusan
      select: 'nama'
    }
  });
}

// Populate semua mahasiswa
async function getAllMahasiswaWithJurusan() {
  return await Mahasiswa.find({ aktif: true })
    .populate('jurusan', 'kode nama')
    .sort({ nama: 1 })
    .lean(); // kembalikan plain JS object, bukan Mongoose Document (lebih cepat)
}

// ==========================================
// EMBEDDING vs REFERENCING dalam satu schema
// ==========================================
const orderSchema = new Schema({
  // Reference: customer bisa ada di banyak order
  pelanggan: { type: Schema.Types.ObjectId, ref: 'User' },

  // Embedding: detail produk di-embed karena harga bisa berubah
  // (kita ingin simpan harga saat pembelian, bukan harga saat ini)
  items: [{
    produktId:   { type: Schema.Types.ObjectId, ref: 'Produk' },
    nama:        String,   // di-embed karena nama saat beli mungkin berubah
    hargaSaatBeli: Number, // di-embed agar tidak berubah jika harga update
    jumlah:      Number
  }],

  totalHarga:  Number,
  status:      { type: String, enum: ['pending', 'proses', 'selesai', 'batal'] },
  alamatKirim: {            // di-embed karena alamat bisa berubah di kemudian hari
    jalan:    String,
    kota:     String,
    kodePos:  String
  }
});

const { Mahasiswa } = require('../models/Mahasiswa');

// ==========================================
// CONTOH 1: Statistik IPK per Jurusan
// ==========================================
async function statistikPerJurusan() {
  return await Mahasiswa.aggregate([
    // Stage 1: filter hanya mahasiswa aktif
    { $match: { aktif: true } },

    // Stage 2: join dengan collection jurusan
    {
      $lookup: {
        from:         'jurusan',        // nama collection di MongoDB
        localField:   'jurusan',        // field di Mahasiswa
        foreignField: '_id',            // field di Jurusan
        as:           'data_jurusan'    // nama field hasil join
      }
    },

    // Stage 3: pecah array hasil lookup (karena $lookup menghasilkan array)
    { $unwind: '$data_jurusan' },

    // Stage 4: kelompokkan per jurusan dan hitung statistik
    {
      $group: {
        _id:           '$data_jurusan._id',
        namaJurusan:   { $first: '$data_jurusan.nama' },
        totalMahasiswa:{ $sum: 1 },
        rataIPK:       { $avg: '$ipk' },
        ipkTertinggi:  { $max: '$ipk' },
        ipkTerendah:   { $min: '$ipk' }
      }
    },

    // Stage 5: tambah field perhitungan
    {
      $addFields: {
        rataIPK: { $round: ['$rataIPK', 2] }
      }
    },

    // Stage 6: urutkan berdasarkan total mahasiswa
    { $sort: { totalMahasiswa: -1 } }
  ]);
}

// ==========================================
// CONTOH 2: Distribusi Mahasiswa per Kategori IPK
// ==========================================
async function distribusiIPK() {
  return await Mahasiswa.aggregate([
    { $match: { aktif: true } },
    {
      $group: {
        _id: {
          $switch: {
            branches: [
              { case: { $gte: ['$ipk', 3.5] }, then: 'Cumlaude (>= 3.5)' },
              { case: { $gte: ['$ipk', 3.0] }, then: 'Memuaskan (3.0-3.49)' },
              { case: { $gte: ['$ipk', 2.5] }, then: 'Cukup (2.5-2.99)' }
            ],
            default: 'Kurang (< 2.5)'
          }
        },
        jumlah: { $sum: 1 }
      }
    },
    { $sort: { jumlah: -1 } }
  ]);
}

// ==========================================
// CONTOH 3: Pagination dengan total count (satu query!)
// ==========================================
async function getMahasiswaPaginated(halaman = 1, limit = 10) {
  const skip = (halaman - 1) * limit;

  const [hasil] = await Mahasiswa.aggregate([
    { $match: { aktif: true } },
    {
      $facet: {  // dua sub-pipeline paralel
        data: [
          { $sort: { nama: 1 } },
          { $skip: skip },
          { $limit: limit },
          { $project: { nim: 1, nama: 1, ipk: 1 } }
        ],
        total: [
          { $count: 'jumlah' }
        ]
      }
    }
  ]);

  return {
    data:  hasil.data,
    total: hasil.total[0]?.jumlah ?? 0,
    halaman,
    limit,
    totalHalaman: Math.ceil((hasil.total[0]?.jumlah ?? 0) / limit)
  };
}

