const mongoose = require('mongoose');

// ==========================================
// KONFIGURASI KONEKSI YANG ROBUST
// ==========================================
const koneksiOptions = {
  // Timeout settings
  serverSelectionTimeoutMS: 5000,  // gagal setelah 5 detik jika tidak bisa connect
  socketTimeoutMS:          45000, // timeout socket setelah 45 detik idle

  // Connection pool
  maxPoolSize:  10,  // maksimal 10 koneksi bersamaan
  minPoolSize:  2,   // minimal 2 koneksi selalu tersedia

  // Heartbeat: cek koneksi secara berkala
  heartbeatFrequencyMS: 10000  // cek setiap 10 detik
};

const MONGODB_URI = process.env.NODE_ENV === 'production'
  ? process.env.MONGODB_URI          // Atlas di production
  : process.env.MONGODB_URI_DEV;     // lokal di development

async function connectDB() {
  try {
    const conn = await mongoose.connect(MONGODB_URI, koneksiOptions);

    console.log(`✅ MongoDB Atlas terhubung: ${conn.connection.host}`);
    console.log(`📦 Database: ${conn.connection.name}`);

  } catch (err) {
    console.error('❌ Koneksi MongoDB gagal:', err.message);
    process.exit(1); // hentikan aplikasi jika DB tidak bisa diakses
  }
}

// Handle disconnection
mongoose.connection.on('error', (err) => {
  console.error('MongoDB error:', err);
});

mongoose.connection.on('disconnected', () => {
  console.warn('MongoDB terputus — mencoba reconnect...');
});

// Graceful shutdown
const gracefulShutdown = async (signal) => {
  console.log(`${signal} diterima — menutup koneksi MongoDB...`);
  await mongoose.connection.close();
  process.exit(0);
};

process.on('SIGTERM', () => gracefulShutdown('SIGTERM'));
process.on('SIGINT',  () => gracefulShutdown('SIGINT'));

module.exports = connectDB;

// ==========================================
// index.js — entry point
// ==========================================
const express = require('express');
const connectDB = require('./config/database');

const app = express();

// Hubungkan ke database SEBELUM menjalankan server
connectDB().then(() => {
  app.listen(process.env.PORT || 3000, () => {
    console.log(`🚀 Server berjalan di port ${process.env.PORT || 3000}`);
  });
});
